import React, { useState, useEffect } from 'react';
import { SGPASubject, Mark, Credit, asMark, asCredit } from '../src/domain/types';
import { calculateGradePoint, getLetterFromGP } from '../src/domain/grading/engine';
import { isValidCourseCode, sanitizeSubjectName } from '../src/core/validation';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (subject: Partial<SGPASubject>) => void;
  initialData?: Partial<SGPASubject>;
  theme?: any;
  enableCodes: boolean;
}

const SubjectEntryModal: React.FC<Props> = ({
  isOpen,
  onClose,
  onSubmit,
  initialData,
  enableCodes,
}) => {
  const [name, setName] = useState(initialData?.name || '');
  const [code, setCode] = useState(initialData?.code || '');
  const [credits, setCredits] = useState(initialData?.credits?.toString() || '3');
  const [marks, setMarks] = useState(initialData?.marks?.toString() || '');

  useEffect(() => {
    if (isOpen) {
      setName(initialData?.name || '');
      setCode(initialData?.code || '');
      setCredits(initialData?.credits?.toString() || '3');
      setMarks(initialData?.marks?.toString() || '');
    }
  }, [isOpen, initialData]);

  if (!isOpen) return null;

  const numCredits = parseInt(credits);
  const numMarks = marks === '' ? -1 : parseInt(marks);
  const isNameInvalid = name !== '' && !name.trim();
  const isCodeInvalid = enableCodes && code !== '' && !isValidCourseCode(code);
  const isCreditsInvalid =
    credits !== '' && (isNaN(numCredits) || numCredits < 2 || numCredits > 6);
  const isMarksInvalid = marks !== '' && (isNaN(numMarks) || numMarks < 0 || numMarks > 100);
  const isFormValid =
    name.trim() &&
    (!enableCodes || (code && isValidCourseCode(code))) &&
    !isCreditsInvalid &&
    !isMarksInvalid &&
    credits !== '' &&
    marks !== '';

  const handleSave = () => {
    if (!isFormValid) return;
    const gp = calculateGradePoint(asMark(numMarks));
    onSubmit({
      name: sanitizeSubjectName(name),
      code: enableCodes ? code.toUpperCase() : '',
      credits: asCredit(numCredits),
      marks: asMark(numMarks),
      gradePoint: gp,
      gradeLetter: getLetterFromGP(gp),
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-500">
      <div className="bg-bg-surface w-full max-w-lg rounded-[2.5rem] p-10 sm:p-12 border border-white/5 shadow-[0_32px_64px_-16px_rgba(0,0,0,1)] relative overflow-hidden group">
        <div className="absolute top-0 right-0 p-8 opacity-0 group-hover:opacity-10 transition-opacity">
          <span className="material-symbols-outlined text-8xl text-primary">edit_note</span>
        </div>

        <div className="flex justify-between items-start mb-10 relative z-10">
          <div className="space-y-1">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center text-primary">
                <span className="material-symbols-outlined text-[20px]">book</span>
              </div>
              <h3 className="text-[11px] font-black font-headline text-primary uppercase tracking-[0.4em]">
                {initialData?.id ? 'Update Registry' : 'Course Initialization'}
              </h3>
            </div>
            <p className="text-[10px] font-bold font-label text-zinc-600 uppercase tracking-widest pl-1">
              Academic entity parameter entry
            </p>
          </div>
          <button
            onClick={onClose}
            className="w-10 h-10 flex items-center justify-center rounded-xl bg-bg-surface-lowest border border-white/5 text-zinc-600 hover:text-white hover:bg-white/5 transition-all"
          >
            <span className="material-symbols-outlined text-[20px]">close</span>
          </button>
        </div>

        <div className="space-y-8 relative z-10">
          <div className="space-y-3">
            <div className="flex justify-between items-center px-1">
              <label className="text-[9px] font-black font-label text-zinc-500 uppercase tracking-widest ml-1">
                Subject Designation
              </label>
              {isNameInvalid && (
                <span className="text-[8px] font-black text-error uppercase tracking-widest bg-error/10 px-2 py-0.5 rounded-md">
                  Required Field
                </span>
              )}
            </div>
            <input
              type="text"
              placeholder="e.g. Advanced Thermodynamics"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className={`w-full px-6 py-4 bg-bg-surface-lowest border rounded-2xl outline-none text-white font-black text-sm transition-all placeholder:text-zinc-800 shadow-inner-glow ${isNameInvalid ? 'border-error/40 ring-2 ring-error/5' : 'border-white/5 focus:border-primary/50'}`}
            />
          </div>

          {enableCodes && (
            <div className="space-y-3">
              <div className="flex justify-between items-center px-1">
                <label className="text-[9px] font-black font-label text-zinc-500 uppercase tracking-widest ml-1">
                  Course Protocol Code
                </label>
                {isCodeInvalid && (
                  <span className="text-[8px] font-black text-error uppercase tracking-widest bg-error/10 px-2 py-0.5 rounded-md">
                    Format: AB-123
                  </span>
                )}
              </div>
              <input
                type="text"
                placeholder="e.g. PH-201"
                value={code}
                onChange={(e) => setCode(e.target.value)}
                className={`w-full px-6 py-4 bg-bg-surface-lowest border rounded-2xl outline-none text-white font-black font-mono text-sm tracking-widest transition-all placeholder:text-zinc-800 shadow-inner-glow uppercase ${isCodeInvalid ? 'border-error/40 ring-2 ring-error/5' : 'border-white/5 focus:border-primary/50'}`}
              />
            </div>
          )}

          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-3">
              <label className="text-[9px] font-black font-label text-zinc-500 uppercase tracking-widest ml-1">
                Credit Units
              </label>
              <div className="relative group/range">
                <input
                  type="number"
                  min="2"
                  max="6"
                  value={credits}
                  onChange={(e) => setCredits(e.target.value)}
                  className={`w-full px-6 py-5 bg-bg-surface-lowest border rounded-2xl outline-none text-center text-2xl font-black text-primary transition-all shadow-inner-glow ${isCreditsInvalid ? 'border-error/40 ring-1 ring-error/10' : 'border-white/5 focus:border-primary/50'}`}
                />
                <div className="absolute right-4 top-1/2 -translate-y-1/2 opacity-0 group-hover/range:opacity-30 transition-opacity">
                  <span className="text-[9px] font-black text-primary font-mono select-none">
                    Units
                  </span>
                </div>
              </div>
            </div>
            <div className="space-y-3">
              <label className="text-[9px] font-black font-label text-zinc-500 uppercase tracking-widest ml-1">
                Raw Score (%)
              </label>
              <div className="relative group/range">
                <input
                  type="number"
                  min="0"
                  max="100"
                  value={marks}
                  onChange={(e) => setMarks(e.target.value)}
                  placeholder="0—100"
                  className={`w-full px-6 py-5 bg-bg-surface-lowest border rounded-2xl outline-none text-center text-2xl font-black text-primary transition-all placeholder:text-zinc-800 shadow-inner-glow ${isMarksInvalid ? 'border-error/40 ring-1 ring-error/10' : 'border-white/5 focus:border-primary/50'}`}
                />
                <div className="absolute right-4 top-1/2 -translate-y-1/2 opacity-0 group-hover/range:opacity-30 transition-opacity">
                  <span className="text-[9px] font-black text-primary font-mono select-none">
                    %
                  </span>
                </div>
              </div>
            </div>
          </div>

          <div className="pt-6">
            <button
              onClick={handleSave}
              disabled={!isFormValid}
              className="group/save relative w-full h-[60px] bg-primary text-on-primary font-black font-label uppercase tracking-[0.2em] rounded-2xl overflow-hidden transition-all active:scale-[0.98] disabled:opacity-20 disabled:cursor-not-allowed shadow-glow"
            >
              <div className="absolute inset-0 bg-white/10 translate-y-full group-hover/save:translate-y-0 transition-transform duration-300"></div>
              <span className="relative z-10 flex items-center justify-center gap-3">
                <span className="material-symbols-outlined text-[18px]">save</span>
                Finalize Entry
              </span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SubjectEntryModal;

import React, { useState, useEffect, useRef } from 'react';
import { UserInfo } from '../src/domain/types';
import { PROGRAMMES } from '../constants';

interface UserInfoModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (info: UserInfo) => void;
  title: string;
  isCGPA?: boolean;
  rowCount?: number;
  theme?: any;
}

const UserInfoModal: React.FC<UserInfoModalProps> = ({
  isOpen,
  onClose,
  onSubmit,
  title,
  isCGPA,
  rowCount = 0,
}) => {
  const [info, setInfo] = useState<UserInfo>({
    name: '',
    fatherName: '',
    registrationNumber: '',
    programme: PROGRAMMES[0],
    semester: '1',
    section: '',
    subject: '',
    minor: '',
    isCompleted: false,
    totalDuration: '',
    isVerified: false,
    photo: undefined,
  });

  const [formTouched, setFormTouched] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (info.programme === 'Undergraduate (BS)') {
      setInfo((prev) => ({ ...prev, semester: prev.isCompleted ? '8' : '1' }));
    } else if (!info.isCompleted) {
      setInfo((prev) => ({ ...prev, semester: '1' }));
    }
  }, [info.programme, info.isCompleted]);

  if (!isOpen) return null;

  const sanitizeName = (val: string) => val.replace(/[^A-Za-z\s]/g, '');
  const sanitizeSection = (val: string) =>
    val
      .replace(/[^A-Za-z]/g, '')
      .toUpperCase()
      .slice(0, 1);

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setInfo((prev) => ({ ...prev, photo: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const isNameValid = info.name.trim().length > 2;
  const isFatherValid = info.fatherName.trim().length > 2;
  const isRegValid = info.registrationNumber.length === 8;
  const isSectionValid = info.section.length === 1;
  const isSubjectValid = info.subject.trim().length >= 2;

  let cgpaConstraintError = '';
  if (isCGPA) {
    if (info.isCompleted) {
      if (info.programme === 'Undergraduate (BS)') {
        if (rowCount !== 8) cgpaConstraintError = `BS requires 8 semesters (Provided: ${rowCount})`;
      } else {
        const duration = parseInt(info.totalDuration || '0');
        if (!duration || rowCount !== duration)
          cgpaConstraintError = `${duration ? `Required: ${duration}` : 'Total duration needed'}`;
      }
    } else {
      const currentSem = parseInt(info.semester);
      if (rowCount !== currentSem - 1)
        cgpaConstraintError = `Sem ${currentSem} requires ${currentSem - 1} records (Found: ${rowCount})`;
    }
  }

  const isFormValid =
    isNameValid &&
    isFatherValid &&
    isRegValid &&
    isSectionValid &&
    isSubjectValid &&
    info.isVerified &&
    !cgpaConstraintError;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFormValid) return;

    const finalInfo = {
      ...info,
      registrationNumber: `AWKUM-${info.registrationNumber}`,
      semester:
        info.isCompleted && info.programme !== 'Undergraduate (BS)'
          ? info.totalDuration
          : info.semester,
    };

    onSubmit(finalInfo as UserInfo);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/80 backdrop-blur-2xl animate-in fade-in duration-500">
      <div className="w-full max-w-xl rounded-[2.5rem] overflow-hidden shadow-2xl border border-white/5 bg-bg-surface animate-in zoom-in-95 duration-300">
        {/* Header */}
        <div className="p-10 text-center relative overflow-hidden bg-gradient-to-b from-primary/5 to-transparent">
          <div className="relative z-10">
            <h3 className="text-2xl font-black font-headline text-white uppercase tracking-[0.2em] mb-2">
              {title}
            </h3>
            <p className="text-zinc-500 text-[10px] font-bold uppercase tracking-[0.2em]">
              Official AWKUM Credential Verification
            </p>
          </div>
          <div className="absolute top-0 right-0 p-8 opacity-5">
            <span className="material-symbols-outlined text-6xl">verified_user</span>
          </div>
        </div>

        <form
          onSubmit={handleSubmit}
          className="px-10 pb-10 space-y-8 max-h-[70vh] overflow-y-auto custom-scrollbar"
        >
          {/* Identity Section */}
          <section className="space-y-6">
            <div className="flex items-center gap-4">
              <span className="text-[10px] font-black font-label text-primary uppercase tracking-widest">
                Personal Identity
              </span>
              <div className="h-px bg-white/5 flex-1"></div>
            </div>

            <div className="flex flex-col md:flex-row items-center gap-8">
              <div className="relative group">
                <div
                  onClick={() => fileInputRef.current?.click()}
                  className="w-28 h-28 rounded-2xl border-2 border-dashed border-white/10 flex items-center justify-center cursor-pointer overflow-hidden bg-bg-surface-lowest hover:border-primary/50 transition-all duration-500 shadow-xl"
                >
                  {info.photo ? (
                    <img src={info.photo} className="w-full h-full object-cover" />
                  ) : (
                    <span className="material-symbols-outlined text-zinc-700 text-3xl">
                      add_a_photo
                    </span>
                  )}
                  <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-all duration-300">
                    <span className="text-white text-[10px] font-bold uppercase tracking-widest">
                      Update
                    </span>
                  </div>
                </div>
                <input
                  type="file"
                  ref={fileInputRef}
                  className="hidden"
                  accept="image/*"
                  onChange={handlePhotoUpload}
                />
              </div>

              <div className="flex-1 w-full space-y-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black font-label text-zinc-500 uppercase tracking-widest ml-1">
                    Full Name
                  </label>
                  <input
                    type="text"
                    placeholder="Enter full name"
                    value={info.name}
                    onFocus={() => setFormTouched(true)}
                    onChange={(e) => setInfo({ ...info, name: sanitizeName(e.target.value) })}
                    className="w-full px-5 py-3.5 bg-bg-surface-lowest border border-white/5 rounded-xl outline-none focus:border-primary focus:ring-1 focus:ring-primary text-sm font-bold text-white transition-all placeholder:text-zinc-800"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black font-label text-zinc-500 uppercase tracking-widest ml-1">
                    Father's Name
                  </label>
                  <input
                    type="text"
                    placeholder="Enter father's name"
                    value={info.fatherName}
                    onFocus={() => setFormTouched(true)}
                    onChange={(e) => setInfo({ ...info, fatherName: sanitizeName(e.target.value) })}
                    className="w-full px-5 py-3.5 bg-bg-surface-lowest border border-white/5 rounded-xl outline-none focus:border-primary focus:ring-1 focus:ring-primary text-sm font-bold text-white transition-all placeholder:text-zinc-800"
                  />
                </div>
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="text-[9px] font-black font-label text-zinc-500 uppercase tracking-widest ml-1">
                Registration Number
              </label>
              <div className="flex items-center bg-bg-surface-lowest border border-white/5 rounded-xl overflow-hidden focus-within:border-primary transition-all">
                <div className="px-5 py-3.5 bg-white/5 text-[10px] font-black text-zinc-500 uppercase tracking-widest">
                  AWKUM -
                </div>
                <input
                  type="text"
                  maxLength={8}
                  placeholder="00000000"
                  value={info.registrationNumber}
                  onFocus={() => setFormTouched(true)}
                  onChange={(e) =>
                    setInfo({ ...info, registrationNumber: e.target.value.replace(/\D/g, '') })
                  }
                  className="flex-1 bg-transparent px-5 py-3.5 outline-none text-sm font-black tracking-[0.3em] text-white"
                />
              </div>
            </div>
          </section>

          {/* Academic Profile */}
          <section className="space-y-6">
            <div className="flex items-center gap-4">
              <span className="text-[10px] font-black font-label text-primary uppercase tracking-widest">
                Academic Ranking
              </span>
              <div className="h-px bg-white/5 flex-1"></div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[9px] font-black font-label text-zinc-500 uppercase tracking-widest ml-1">
                  Academic Program
                </label>
                <select
                  value={info.programme}
                  onChange={(e) => setInfo({ ...info, programme: e.target.value })}
                  className="w-full px-5 py-3.5 bg-bg-surface-lowest border border-white/5 rounded-xl outline-none focus:border-primary text-sm font-bold text-white appearance-none cursor-pointer hover:bg-white/5 transition-all"
                >
                  {PROGRAMMES.map((p) => (
                    <option key={p} value={p} className="bg-zinc-900">
                      {p}
                    </option>
                  ))}
                </select>
              </div>

              <div className="space-y-1.5">
                <label className="text-[9px] font-black font-label text-zinc-500 uppercase tracking-widest ml-1">
                  {info.isCompleted ? 'Total Duration' : 'Target Semester'}
                </label>
                {isCGPA && info.isCompleted && info.programme !== 'Undergraduate (BS)' ? (
                  <input
                    type="number"
                    min="1"
                    max="12"
                    placeholder="Semesters"
                    value={info.totalDuration}
                    onChange={(e) => setInfo({ ...info, totalDuration: e.target.value })}
                    className="w-full px-5 py-3.5 bg-bg-surface-lowest border border-white/5 rounded-xl outline-none focus:border-primary text-sm font-black text-center text-white"
                  />
                ) : (
                  <select
